css:
.tn-header {
  margin-bottom: 1.0mm;
}
.tn-title {
  font-weight: 700;
  font-size: 8pt;
  margin: 0;
}
.tn-meta {
  color: #555;
  font-size: 5.8pt;
  margin-top: 0.2mm;
}
.tn-meta .sep {
  color: #aaa;
  padding: 0 0.6mm;
}
.tn-bemerkung {
  margin-top: 0.6mm;
  font-size: 5.8pt;
  color: #333;
  font-style: italic;
}
.tn-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 6.35pt;
  line-height: 1.16;
  table-layout: fixed;
}
.tn-table th {
  text-align: left;
  font-size: 5.2pt;
  color: #555;
  text-transform: uppercase;
  letter-spacing: 0;
  border-bottom: 0.3pt solid #333;
  padding: 0.28mm 0.5mm !important;
  font-weight: 600;
}
.tn-table td {
  padding: 0.3mm 0.5mm !important;
  vertical-align: top !important;
  border-bottom: 0.25pt solid #ccc;
}
.tn-table tr.eintrag-row {
  break-inside: avoid;
  page-break-inside: avoid;
}
.tn-wohnung-id {
  font-weight: 700;
  font-size: 6.7pt;
  text-align: right;
  color: #111;
  white-space: nowrap;
  padding-right: 0.7mm;
}
.tn-wohnung {
  font-weight: 600;
  white-space: nowrap;
  font-size: 6.35pt;
  overflow: hidden;
}
.tn-imm {
  color: #777;
  font-size: 5.25pt;
  font-weight: 400;
  margin-left: 0.45mm;
}
.tn-mieter-cell,
.tn-phone-cell {
  white-space: nowrap;
  overflow: hidden;
}
.tn-subrow {
  display: block;
  white-space: nowrap;
  min-height: 2.2mm;
  line-height: 1.16;
}
.tn-mieter {
  font-weight: 500;
}
.tn-rolle {
  color: #777;
  font-size: 5.25pt;
  margin-left: 0.25mm;
}
.tn-phone-number {
  white-space: nowrap;
}
.tn-phone-gap {
  display: inline-block;
  width: 1.1mm;
}
.tn-empty {
  color: #bbb;
}

html:
{%- set groups = doc.get_grouped_eintraege() -%}
{%- set show_immobilie = not doc.immobilie -%}
{%- set anzahl_eintraege = doc.eintraege|length -%}

<div class="tn-header">
  <h1 class="tn-title">{{ doc.titel or _("Telefonnummern Mieter") }}</h1>
  <div class="tn-meta">
    {{ _("Stichtag") }}: {{ frappe.utils.formatdate(doc.stichtag) }}
    {%- if doc.immobilie %}
      <span class="sep">·</span>{{ _("Immobilie") }}: {{ doc.immobilie }}
    {%- endif %}
    <span class="sep">·</span>{{ _("Einträge") }}: {{ anzahl_eintraege }}
  </div>
  {%- if doc.bemerkung %}
    <div class="tn-bemerkung">{{ doc.bemerkung }}</div>
  {%- endif %}
</div>

{%- if not groups %}
  <p class="tn-empty">{{ _('Keine Einträge vorhanden. Bitte im Formular auf "Einträge laden" klicken.') }}</p>
{%- else %}
  <table class="tn-table">
    <thead>
      <tr>
        <th style="width: 6%; text-align: right;">{{ _("ID") }}</th>
        <th style="width: 24%">{{ _("Wohnung") }}</th>
        <th style="width: 28%">{{ _("Mieter") }}</th>
        <th style="width: 42%">{{ _("Telefon / Mobil") }}</th>
      </tr>
    </thead>
    <tbody>
      {%- for grp in groups %}
        <tr class="eintrag-row">
          <td class="tn-wohnung-id">{{ grp.wohnung_id if grp.wohnung_id is not none else '' }}</td>
          <td class="tn-wohnung">
            {{ grp.wohnung }}
          </td>
          <td class="tn-mieter-cell">
            {%- for m in grp.mieter -%}
              <div class="tn-subrow">
                <span class="tn-mieter">{{ m.name }}</span>
                {%- if m.rolle and m.rolle != 'Hauptmieter' %}<span class="tn-rolle">({{ m.rolle }})</span>{% endif -%}
              </div>
            {%- endfor %}
          </td>
          <td class="tn-phone-cell">
            {%- for m in grp.mieter -%}
              <div class="tn-subrow">
                {%- if m.telefon %}<span class="tn-phone-number">{{ m.telefon }}</span>{% endif -%}
                {%- if m.telefon and m.mobil %}<span class="tn-phone-gap"></span>{% endif -%}
                {%- if m.mobil %}<span class="tn-phone-number">{{ m.mobil }}</span>{% endif -%}
                {%- if not m.telefon and not m.mobil %}<span class="tn-empty">—</span>{% endif -%}
              </div>
            {%- endfor %}
          </td>
        </tr>
      {%- endfor %}
    </tbody>
  </table>
{%- endif %}
